Here is a JavaScript function that takes an array of 5 numbers as input and checks if any of the numbers is a valid prime number:
```
function checkPrimes(arr) {
  for (let num of arr) {
    if (isPrime(num)) {
      console.log(num);
    }
  }
}

function isPrime(n) {
  if (n <= 1) return false;
  for (let i = 2; i * i <= n; i++) {
    if (n % i === 0) return false;
  }
  return true;
}

